async function migrar() {
  // Buscar IDs já existentes no Supabase
  const { data: existentes } = await supabase
    .from('bares')
    .select('id');
  
  const idsExistentes = new Set(existentes.map(b => b.id));
  
  const novos = BARES_ESTATICO.filter(b => !idsExistentes.has(b.id));
  console.log(`Bares novos para inserir: ${novos.length}`);

  const baresFormatados = novos.map(b => ({
    id:         b.id,
    nome:       b.nome,
    endereco:   b.end || null,
    bairro:     b.bairro || null,
    regiao:     b.regiao || null,
    lat:        b.lat || null,
    lng:        b.lng || null,
    horario:    b.horario || null,
    telefone:   b.telefone || null,
    instagram:  b.instagram || null,
    promocao:   b.promocao || null,
    prato:      b.prato || null,
    link:       b.link || null,
    descricao:  b.descricao || null,
    tier:       b.tier || null,
    xp:         b.xp || 0,
    avaliacoes: b.avaliacoes || 0,
    rating:     b.rating || null,
    verificado: b.verificado || false,
    tags:       b.tags || [],
    ativo:      true,
  }));

  const LOTE = 100;
  let inseridos = 0;

  for (let i = 0; i < baresFormatados.length; i += LOTE) {
    const lote = baresFormatados.slice(i, i + LOTE);
    const { error } = await supabase.from('bares').upsert(lote, { onConflict: 'id' });
    if (error) console.error('Erro:', error.message);
    else { inseridos += lote.length; console.log(`Inseridos: ${inseridos}/${baresFormatados.length}`); }
  }

  console.log('Concluído.');
}

migrar();